der: 1px solid var(--border-color);\n  border-radius: 20px;\n  padding: 4px 12px;\n  transition: border-color 0.2s;\n}\n.image-hosting_search-box:focus-within {\n  border-color: var(--primary-color);\n  box-shadow: 0 0 0 2px rgba(52, 152, 219, 0.1);\n}\n.search-icon { font-size: 12px; color: var(--text-muted); margin-right: 8px; }\n.clear-icon { cursor: pointer; color: var(--text-muted); transition: color 0.15s; }\n.clear-icon:hover { color: var(--text-main); }\n.search-input {\n  flex: 1;\n  background: none;\n  border: none;\n  color: var(--text-main);\n  font-size: 13px;\n  outline: none;\n  width: 100%;\n}\n\n.image-hosting_batch-bar {\n  display: flex;\n  align-items: center;\n  gap: 12px;\n}\n.batch-checkbox {\n  display: flex;\n  align-items: center;\n  gap: 6px;\n  font-size: 12px;\n  cursor: pointer;\n  color: var(--text-main);\n}\n.batch-actions {\n  display: flex;\n  align-items: center;\n  gap: 6px;\n  opacity: 0;\n  pointer-events: none;\n  transform: translateX(10px);\n  transition: all 0.2s cubic-bezier(0.175, 0.885, 0.32, 1.275);\n}\n.batch-actions--active {\n  opacity: 1;\n  pointer-events: auto;\n  transform: translateX(0);\n}\n.selected-count {\n  font-size: 11px;\n  background: var(--primary-color);\n  color: white;\n  padding: 2px 6px;\n  border-radius: 10px;\n}\n.icon-action-btn {\n  background: none;\n  border: none;\n  color: var(--text-muted);\n  cursor: pointer;\n  width: 28px; height: 28px;\n  border-radius: 6px;\n  display: flex; align-items: center; justify-content: center;\n  transition: all 0.2s;\n}\n.icon-action-btn:hover { background: rgba(255,255,255,0.1); color: var(--text-main); }\n.icon-action-btn.delete-btn:hover { background: rgba(255,91,91,0.1); color: var(--danger-color); }\n\n/* List Container & Empty State */\n.image-hosting_empty-state {\n  text-align: center;\n  padding: 40px 0;\n  color: var(--text-muted);\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  gap: 10px;\n}\n.empty-icon {\n  font-size: 40px;\n  opacity: 0.3;\n}\n\n.image-hosting_grid {\n  display: grid;\n  grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));\n  gap: 12px;\n  margin-top: 10px;\n}\n\n/* List Transitions */\n.list-enter-active, .list-leave-active { transition: all 0.3s ease; }\n.list-enter-from { opacity: 0; transform: translateY(15px); }\n.list-leave-to { opacity: 0; transform: scale(0.9); }\n\n/* Card Design */\n.image-hosting_card {\n  background: var(--card-bg);\n  border: 1px solid var(--border-color);\n  border-radius: 10px;\n  padding: 10px;\n  display: flex;\n  align-items: center;\n  gap: 12px;\n  position: relative;\n  transition: all 0.2s;\n  overflow: hidden;\n}\n.image-hosting_card:hover {\n  transform: translateY(-2px);\n  box-shadow: 0 4px 15px rgba(0,0,0,0.2);\n  border-color: rgba(255,255,255,0.2);\n}\n.image-hosting_card.is-selected {\n  border-color: var(--primary-color);\n  background: rgba(52, 152, 219, 0.05);\n}\n\n.card-select {\n  display: flex;\n  align-items: center;\n}\n\n.card-preview {\n  width: 60px;\n  height: 60px;\n  border-radius: 6px;\n  overflow: hidden;\n  position: relative;\n  cursor: pointer;\n  flex-shrink: 0;\n  background: #000;\n}\n.card-preview img {\n  width: 100%;\n  height: 100%;\n  object-fit: cover;\n  transition: transform 0.3s ease;\n}\n.card-preview:hover img {\n  transform: scale(1.1);\n}\n.preview-overlay {\n  position: absolute;\n  top: 0; left: 0; right: 0; bottom: 0;\n  background: rgba(0,0,0,0.5);\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  opacity: 0;\n  transition: opacity 0.2s;\n  color: white;\n  font-size: 16px;\n}\n.card-preview:hover .preview-overlay { opacity: 1; }\n\n.embedded-badge {\n  position: absolute;\n  top: 4px; right: 4px;\n  background: rgba(0,0,0,0.7);\n  color: #f39c12;\n  font-size: 10px;\n  padding: 2px 4px;\n  border-radius: 4px;\n  backdrop-filter: blur(2px);\n}\n\n.card-info {\n  flex: 1;\n  min-width: 0;\n  display: flex;\n  flex-direction: column;\n  gap: 4px;\n}\n.card-name-row {\n  display: flex;\n  align-items: center;\n  gap: 4px;\n}\n.card-name {\n  font-size: 13px;\n  font-weight: 500;\n  white-space: nowrap;\n  overflow: hidden;\n  text-overflow: ellipsis;\n  flex: 1;\n}\n.name-edit-input {\n  flex: 1;\n  width: 100%;\n  background: rgba(0,0,0,0.4);\n  border: 1px solid var(--primary-color);\n  color: white;\n  border-radius: 4px;\n  padding: 2px 6px;\n  font-size: 12px;\n  outline: none;\n}\n.small-icon-btn {\n  background: none;\n  border: none;\n  color: var(--text-muted);\n  cursor: pointer;\n  font-size: 11px;\n  padding: 2px 4px;\n  border-radius: 4px;\n  transition: all 0.2s;\n}\n.small-icon-btn:hover { background: rgba(255,255,255,0.1); color: var(--text-main); }\n.small-icon-btn.success:hover { color: var(--success-color); }\n.small-icon-btn.danger:hover { color: var(--danger-color); }\n\n.card-meta {\n  font-size: 11px;\n  color: var(--text-muted);\n  display: flex;\n  align-items: center;\n  gap: 6px;\n}\n.meta-dot { opacity: 0.5; font-size: 8px; }\n.meta-type {\n  background: rgba(255,255,255,0.1);\n  padding: 1px 4px;\n  border-radius: 3px;\n  font-size: 10px;\n}\n\n.card-actions {\n  display: flex;\n  align-items: center;\n  gap: 6px;\n  margin-top: 4px;\n}\n.action-btn {\n  background: rgba(255,255,255,0.05);\n  border: 1px solid transparent;\n  color: var(--text-main);\n  padding: 4px 8px;\n  border-radius: 4px;\n  font-size: 11px;\n  cursor: pointer;\n  display: flex;\n  align-items: center;\n  gap: 4px;\n  transition: all 0.2s;\n  flex: 1;\n  justify-content: center;\n}\n.action-btn:hover {\n  background: rgba(255,255,255,0.1);\n  border-color: rgba(255,255,255,0.1);\n}\n.action-btn.danger-icon {\n  flex: 0 0 auto;\n  color: var(--text-muted);\n}\n.action-btn.danger-icon:hover {\n  color: var(--danger-color);\n  border-color: rgba(255,91,91,0.2);\n  background: rgba(255,91,91,0.05);\n}\n\n/* Fullscreen Preview */\n.fade-enter-active, .fade-leave-active { transition: opacity 0.25s ease; }\n.fade-ent